   433|    let settled = false;
   434|
   435|    const timeout = setTimeout(() => {
   436|      if (settled) {
   437|        return;
   438|      }
   439|
   440|      settled = true;
   441|      console.log('[Auth] Operation timed out:', label, timeoutMs, 'ms');
   442|      resolve(fallbackValue);
   443|    }, timeoutMs);
   444|
   445|    void operation()
   446|      .then((result) => {
   447|        if (settled) {
   448|          return;
   449|        }
   450|
   451|        settled = true;
   452|        clearTimeout(timeout);
   453|        resolve(result);
   454|      })
   455|      .catch((error) => {
   456|        if (settled) {
   457|          return;
   458|        }
   459|
   460|        settled = true;
   461|        clearTimeout(timeout);
   462|        reject(error);
   463|      });
   464|  });
