   155|export const VALID_PHOTO_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp', '.heic', '.heif'] as const;
   156|export const VALID_PHOTO_MIME_PREFIXES = ['image/', 'data:image/'] as const;
   157|export const MAX_PHOTO_URL_LENGTH = 2048;
   158|export const MAX_PHOTOS_PER_DEAL = 50;
   159|
   160|export function isValidPhotoUrl(url: string): boolean {
   161|  if (!url || typeof url !== 'string') return false;
   162|  if (url.length < 5 || url.length > MAX_PHOTO_URL_LENGTH) return false;
   163|
   164|  const lower = url.toLowerCase().trim();
   165|  if (lower.startsWith('data:image/')) return true;
   166|  if (lower.startsWith('http://') || lower.startsWith('https://')) {
   167|    const hasImageExtension = VALID_PHOTO_EXTENSIONS.some(ext => {
   168|      const urlWithoutQuery = lower.split('?')[0];
   169|      return urlWithoutQuery.endsWith(ext);
   170|    });
   171|    if (hasImageExtension) return true;
   172|    if (lower.includes('/image') || lower.includes('unsplash') || lower.includes('cloudinary') || lower.includes('r2.dev') || lower.includes('supabase')) {
   173|      return true;
   174|    }
   175|    return true;
   176|  }
   177|
   178|  return false;
   179|}
   180|
   181|export function sanitizePhotos(photos: unknown): string[] {
   182|  if (!photos) return [];
   183|  if (!Array.isArray(photos)) {
   184|    if (typeof photos === 'string') {
   185|      try {
   186|        const parsed = JSON.parse(photos);
   187|        if (Array.isArray(parsed)) return sanitizePhotos(parsed);
   188|      } catch {
   189|        return [];
   190|      }
   191|    }
   192|    return [];
   193|  }
   194|  return photos
   195|    .filter((p): p is string => typeof p === 'string' && isValidPhotoUrl(p))
   196|    .slice(0, MAX_PHOTOS_PER_DEAL);
