   199|export function mergeMemberRegistryRecords(
   200|  existing: MemberRegistryRecord[],
   201|  incoming: MemberRegistryRecord[]
   202|): MemberRegistryRecord[] {
   203|  const registry = new Map<string, MemberRegistryRecord>();
   204|  const aliasToPrimary = new Map<string, string>();
   205|
   206|  const upsertRecord = (record: MemberRegistryRecord) => {
   207|    const aliases = getRecordAliases(record);
   208|    const matchedPrimaryKeys = Array.from(
   209|      new Set(
   210|        aliases
   211|          .map((alias) => aliasToPrimary.get(alias))
   212|          .filter((value): value is string => typeof value === 'string' && value.length > 0)
   213|      )
   214|    );
   215|
   216|    const primaryKey = matchedPrimaryKeys[0] ?? getRecordKey(record);
   217|    let mergedRecord: MemberRegistryRecord | null = registry.get(primaryKey) ?? null;
   218|
   219|    for (const duplicatePrimaryKey of matchedPrimaryKeys.slice(1)) {
   220|      const duplicateRecord = registry.get(duplicatePrimaryKey);
   221|      if (!duplicateRecord) continue;
   222|
   223|      mergedRecord = mergedRecord
   224|        ? mergeTwoMemberRegistryRecords(mergedRecord, duplicateRecord)
   225|        : duplicateRecord;
   226|
   227|      registry.delete(duplicatePrimaryKey);
   228|      for (const duplicateAlias of getRecordAliases(duplicateRecord)) {
   229|        aliasToPrimary.set(duplicateAlias, primaryKey);
   230|      }
   231|    }
   232|
   233|    mergedRecord = mergedRecord
   234|      ? mergeTwoMemberRegistryRecords(mergedRecord, record)
   235|      : record;
   236|
   237|    registry.set(primaryKey, mergedRecord);
   238|    for (const alias of getRecordAliases(mergedRecord)) {
   239|      aliasToPrimary.set(alias, primaryKey);
   240|    }
   241|  };
   242|
   243|  for (const record of sortMemberRegistryRecords(existing)) {
   244|    upsertRecord(record);
   245|  }
   246|
   247|  for (const record of incoming) {
   248|    upsertRecord(record);
   249|  }
   250|
   251|  return sortMemberRegistryRecords(Array.from(registry.values())).slice(0, MEMBER_REGISTRY_MAX_ITEMS);
   252|}
