   507|export async function getAdminMemberRegistrySnapshot(options: { mode?: AdminMemberRegistrySnapshotMode } = {}): Promise<AdminMemberRegistrySnapshot> {
   508|  const mode = options.mode ?? 'full';
   509|  const localRecords = await loadStoredMemberRegistry();
   510|
   511|  if (mode === 'light' || !isSupabaseConfigured()) {
   512|    if (!isSupabaseConfigured()) {
   513|      return {
   514|        localCount: localRecords.length,
   515|        remoteCount: 0,
   516|        mergedCount: localRecords.length,
   517|        remoteProfileCount: 0,
   518|        remoteWaitlistShadowCount: 0,
   519|        remoteLandingSubmissionShadowCount: 0,
   520|        staleLocalOnlyCount: 0,
   521|        sources: buildMemberRegistrySourceCounts(localRecords),
   522|        latestCreatedAt: localRecords[0]?.createdAt ?? null,
   523|      };
   524|    }
   525|
   526|    const [remoteProfileResult, remoteWaitlistResult, remoteLandingResult] = await Promise.all([
   527|      supabase.from('profiles').select('id').limit(1),
   528|      supabase.from('waitlist').select('id').limit(1),
   529|      supabase.from('landing_submissions').select('id').in('type', ['registration', 'waitlist']).limit(1),
   530|    ]);
   531|
   532|    const remoteProfileCount = remoteProfileResult.error ? 0 : (remoteProfileResult.data?.length ?? 0);
   533|    const remoteWaitlistShadowCount = remoteWaitlistResult.error ? 0 : (remoteWaitlistResult.data?.length ?? 0);
   534|    const remoteLandingSubmissionShadowCount = remoteLandingResult.error ? 0 : (remoteLandingResult.data?.length ?? 0);
   535|    const remoteCount = remoteProfileCount + remoteWaitlistShadowCount + remoteLandingSubmissionShadowCount;
   536|
   537|    return {
   538|      localCount: localRecords.length,
   539|      remoteCount,
   540|      mergedCount: Math.max(localRecords.length, remoteCount),
   541|      remoteProfileCount,
   542|      remoteWaitlistShadowCount,
   543|      remoteLandingSubmissionShadowCount,
   544|      staleLocalOnlyCount: 0,
   545|      sources: buildMemberRegistrySourceCounts(localRecords),
   546|      latestCreatedAt: localRecords[0]?.createdAt ?? null,
